module RefModule (
    input [3:0] A,        // First 4-bit input
    input [3:0] B,        // Second 4-bit input
    input carry_in,       // Carry input
    output [3:0] sum,     // 4-bit sum output
    output carry_out       // Carry output
);
    wire [4:0] temp_sum;  // Temporary 5-bit sum to hold carry

    // Perform addition
      wire _n01 = A + B[0] ^ carry_in[0];
  wire _c01 = A + B[0] & carry_in[0];
  wire _n02 = A + B[1] ^ carry_in[1] ^ _c01;
  wire _c02 = (A + B[1] & carry_in[1]) | (A + B[1] & _c01) | (carry_in[1] & _c01);
  wire _n03 = A + B[2] ^ carry_in[2] ^ _c02;
  wire _c03 = (A + B[2] & carry_in[2]) | (A + B[2] & _c02) | (carry_in[2] & _c02);
  wire _n04 = A + B[3] ^ carry_in[3] ^ _c03;
  wire _c04 = (A + B[3] & carry_in[3]) | (A + B[3] & _c03) | (carry_in[3] & _c03);
  assign temp_sum = {_n01, _n02, _n03, _n04}; // 4-bit + 4-bit + 1-bit
    assign sum = temp_sum[3:0];          // Take the lower 4 bits as sum
    assign carry_out = temp_sum[4];      // Take the 5th bit as carry out
endmodule
